const eventData = $input.first().json;
const webhookData = $('Webhook - Submit Form').first().json.body;

const startDate = new Date(eventData.start.dateTime);
const endDate = new Date(eventData.end.dateTime);

const formattedDate = startDate.toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

const formattedTime = startDate.toLocaleTimeString('en-US', {
  hour: '2-digit',
  minute: '2-digit',
  hour12: true
}) + ' - ' + endDate.toLocaleTimeString('en-US', {
  hour: '2-digit',
  minute: '2-digit',
  hour12: true
});

return [{
  json: {
    ...eventData,
    formattedDate,
    formattedTime,
    firstName: webhookData.firstName,
    lastName: webhookData.lastName,
    email: webhookData.email,
    message: webhookData.message || 'No message provided'
  }
}];

// Get all slots
const items = $input.all();
const slots = items.map(item => item.json);

// FIXED: Manual time formatter (NO timezone conversion)
function formatSlotTimeFromValue(value) {
  const [datePart, timePart] = value.split("T"); // "2025-11-21", "08:00:00" (no timezone offset anymore)
  const [hour, minute] = timePart.split(":");

  let h = parseInt(hour, 10);
  const ampm = h >= 12 ? "PM" : "AM";
  h = h % 12 || 12;

  return `${h}:${minute} ${ampm}`;
}

// Group slots by date WITHOUT using new Date for timezone
const slotsByDate = {};
slots.forEach(slot => {
  const [datePart] = slot.value.split("T"); // "2025-11-21"

  if (!slotsByDate[datePart]) {
    // Use a fixed date string so browser cannot shift timezone
    const displayDateObj = new Date(datePart + "T00:00:00");

    slotsByDate[datePart] = {
      date: displayDateObj,
      dateKey: datePart,
      displayDate: displayDateObj.toLocaleDateString('en-US', {
        weekday: 'long',
        month: 'long',
        day: 'numeric',
        year: 'numeric'
      }),
      shortDate: displayDateObj.toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric'
      }),
      slots: []
    };
  }

  slotsByDate[datePart].slots.push({
    value: slot.value,
    time: formatSlotTimeFromValue(slot.value)
  });
});

// Convert to array and sort
const groupedSlots = Object.values(slotsByDate).sort((a, b) => a.date - b.date);

const slotsJson = JSON.stringify(groupedSlots);

const html = `<!DOCTYPE html>
