            if (e.key === 'ArrowLeft' && currentDayIndex > 0) {
                renderDay(currentDayIndex - 1);
            } else if (e.key === 'ArrowRight' && currentDayIndex < slotsByDate.length - 1) {
                renderDay(currentDayIndex + 1);
            }
        });

        // Form validation
        document.getElementById('bookingForm').addEventListener('submit', function(e) {
            if (!selectedSlotInput.value) {
                e.preventDefault();
                alert('Please select a time slot first');
            }
        });

        // Initialize with first day
        if (slotsByDate.length > 0) {
            renderDay(0);
            submitButton.disabled = true;
        } else {
            currentDateDisplay.textContent = 'No available dates';
            timeSlotsContainer.innerHTML = '<div class="no-slots-message">😔 No available slots in the next 30 days</div>';
            prevButton.disabled = true;
            nextButton.disabled = true;
            submitButton.disabled = true;
        }
    </script>
