// PROPER TIMEZONE FIX
// Server timezone: Berlin (CET/CEST, UTC+1)
// Target timezone: Greece (EET/EEST, UTC+2)
// Difference: Greece is 1 hour ahead of Berlin

// Configuration
const workingDays = [1, 2, 3, 4, 5];
const startHour = 9;
const endHour = 14;
const slotDuration = 30;

const now = new Date();
const inputItems = $input.all();

// Get existing events - only timed events within 24 hours
const existingEvents = [];
if (inputItems.length > 0) {
  for (const item of inputItems) {
    const event = item.json;

    if (!event.start || !event.start.dateTime) {
      continue;
    }

    const eventStart = new Date(event.start.dateTime);
    const eventEnd = new Date(event.end.dateTime);
    const eventDurationHours = (eventEnd - eventStart) / (1000 * 60 * 60);

    if (eventDurationHours > 24) {
      continue;
    }

    const windowEnd = new Date(now);
    windowEnd.setDate(now.getDate() + 30);

    if (eventStart < windowEnd && eventEnd > now) {
      existingEvents.push({ start: eventStart, end: eventEnd });
    }
  }
}

// Generate slots
const slots = [];

for (let day = 0; day < 30; day++) {
  const currentDate = new Date(now);
  currentDate.setDate(now.getDate() + day);

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth() + 1;
  const dayOfMonth = currentDate.getDate();
  const dayOfWeek = currentDate.getDay();

  if (!workingDays.includes(dayOfWeek)) continue;

  for (let hour = startHour; hour < endHour; hour++) {
    for (let minute = 0; minute < 60; minute += slotDuration) {
      // Create slot time with EXPLICIT Greek timezone offset
      // This tells Google Calendar: "This is the time in Greece (UTC+2)"
      const slotStartString = `${year}-${String(month).padStart(2, '0')}-${String(dayOfMonth).padStart(2, '0')}T${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}:00+02:00`;
      const slotStart = new Date(slotStartString);
      const slotEnd = new Date(slotStart.getTime() + slotDuration * 60000);

      if (slotStart <= now) continue;

      let isAvailable = true;
      for (const event of existingEvents) {
        if ((slotStart >= event.start && slotStart < event.end) ||
            (slotEnd > event.start && slotEnd <= event.end) ||
            (slotStart <= event.start && slotEnd >= event.end)) {
          isAvailable = false;
          break;
        }
      }

      if (isAvailable) {
        // CRITICAL: Send the FULL timestamp WITH timezone to Google Calendar
        // This ensures Google knows it's Greek time, not Berlin time
        const valueWithTimezone = slotStartString;

        // Format label for display
        const weekdays = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        const months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

        const displayHour12 = hour % 12 || 12;
        const ampm = hour >= 12 ? 'PM' : 'AM';

        const label = `${weekdays[dayOfWeek]}, ${months[month - 1]} ${dayOfMonth}, ${year} at ${displayHour12}:${String(minute).padStart(2, '0')} ${ampm}`;

        slots.push({
          value: valueWithTimezone,
          label: label
        });
      }
    }
  }
}

if (slots.length === 0) {
  return [{ json: { noSlots: true, slots: [] } }];
}

return slots.map(slot => ({ json: slot }));
